import{_ as a,c as e,o as t,a4 as r}from"./chunks/framework.nQaBHiNx.js";const b=JSON.parse('{"title":"第二章 把信息装到名字里","description":"","frontmatter":{"permalink":"/note/the-art-of-readable-code/02.html"},"headers":[],"relativePath":"computer/book/the-art-of-readable-code/02-第二章 把信息装到名字里.md","filePath":"computer/book/the-art-of-readable-code/02-第二章 把信息装到名字里.md"}'),o={name:"computer/book/the-art-of-readable-code/02-第二章 把信息装到名字里.md"},l=r('<h1 id="第二章-把信息装到名字里" tabindex="-1">第二章 把信息装到名字里 <a class="header-anchor" href="#第二章-把信息装到名字里" aria-label="Permalink to &quot;第二章 把信息装到名字里&quot;">​</a></h1><h2 id="选择专业的词" tabindex="-1">选择专业的词 <a class="header-anchor" href="#选择专业的词" aria-label="Permalink to &quot;选择专业的词&quot;">​</a></h2><h2 id="避免泛泛的名字" tabindex="-1">避免泛泛的名字 <a class="header-anchor" href="#避免泛泛的名字" aria-label="Permalink to &quot;避免泛泛的名字&quot;">​</a></h2><h2 id="用具体的名字代替抽象的名字" tabindex="-1">用具体的名字代替抽象的名字 <a class="header-anchor" href="#用具体的名字代替抽象的名字" aria-label="Permalink to &quot;用具体的名字代替抽象的名字&quot;">​</a></h2><h2 id="使用前缀或者后缀来给名字附带更多信息" tabindex="-1">使用前缀或者后缀来给名字附带更多信息 <a class="header-anchor" href="#使用前缀或者后缀来给名字附带更多信息" aria-label="Permalink to &quot;使用前缀或者后缀来给名字附带更多信息&quot;">​</a></h2><h2 id="决定名字的长度" tabindex="-1">决定名字的长度 <a class="header-anchor" href="#决定名字的长度" aria-label="Permalink to &quot;决定名字的长度&quot;">​</a></h2><h2 id="利用名字的格式来表达含义" tabindex="-1">利用名字的格式来表达含义 <a class="header-anchor" href="#利用名字的格式来表达含义" aria-label="Permalink to &quot;利用名字的格式来表达含义&quot;">​</a></h2><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>本章唯一的主题是：把信息塞入名字中。这句话的含义是，读者仅通过读到名字就可以获得大量信息。</p><p>下面是讨论过的几个小提示：</p><ul><li>使用专业的的单词——例如，不用 Get ，而用 Fetch 或者 Download 可能会更好，这由上下文决定。</li><li>避免空泛的名字，像 tmp 和 retval ，除非使用它们有特殊的理由。</li><li>使用具体的名字来更细致地描述事物——ServerCanStart() 这个名字就比 CanListenOnPort() 更不清楚。</li><li>给变量名带上重要的细节——例如，在值为毫秒的变量后加上 _ms。</li><li>为作用域大的名字采用更长那个的名字——不要用让人费解的一个或两个字母的名字来命名。</li><li>有目的的使用大小写、下划线</li></ul>',11),i=[l];function h(n,d,c,_,s,u){return t(),e("div",null,i)}const f=a(o,[["render",h]]);export{b as __pageData,f as default};
